from __future__ import annotations

import http.client
import json
import os
import re
import threading
from dataclasses import dataclass
from typing import Any
from urllib.parse import urlparse


DEFAULT_CHAT_API = "http://127.0.0.1:8080/v1/chat/completions"
DEFAULT_HEALTH_URL = "http://127.0.0.1:8080/health"


@dataclass
class ModelReply:
    ok: bool
    text: str
    model: str
    error: str
    raw: dict[str, Any] | None = None


class ModelAdapter:
    """Small standard-library adapter for FOXAI's local OpenAI-compatible route."""

    def __init__(
        self,
        api_url: str | None = None,
        health_url: str | None = None,
    ) -> None:
        self.api_url = api_url or os.environ.get("FOXAI_CHAT_API", DEFAULT_CHAT_API)
        self.health_url = health_url or os.environ.get(
            "FOXAI_CHAT_HEALTH", DEFAULT_HEALTH_URL
        )
        self._connection_lock = threading.RLock()
        self._connection: http.client.HTTPConnection | None = None
        self._cancelled = threading.Event()

    def cancel(self) -> None:
        self._cancelled.set()
        with self._connection_lock:
            connection = self._connection
        if connection is not None:
            try:
                connection.close()
            except Exception:
                pass

    def reset_cancel(self) -> None:
        self._cancelled.clear()

    @staticmethod
    def _connection_for(url: str, timeout: float) -> tuple[http.client.HTTPConnection, str]:
        parsed = urlparse(url)
        if parsed.scheme not in {"http", "https"} or not parsed.hostname:
            raise ValueError(f"Unsupported local-model URL: {url}")
        port = parsed.port or (443 if parsed.scheme == "https" else 80)
        cls = http.client.HTTPSConnection if parsed.scheme == "https" else http.client.HTTPConnection
        connection = cls(parsed.hostname, port, timeout=timeout)
        path = parsed.path or "/"
        if parsed.query:
            path += "?" + parsed.query
        return connection, path

    def is_online(self, timeout: float = 3.0) -> bool:
        try:
            connection, path = self._connection_for(self.health_url, timeout)
            with self._connection_lock:
                self._connection = connection
            connection.request("GET", path, headers={"Accept": "application/json"})
            response = connection.getresponse()
            response.read()
            return 200 <= response.status < 500
        except Exception:
            return False
        finally:
            with self._connection_lock:
                connection = self._connection
                self._connection = None
            if connection is not None:
                try:
                    connection.close()
                except Exception:
                    pass

    def _chat(
        self,
        messages: list[dict[str, str]],
        *,
        temperature: float = 0.1,
        max_tokens: int = 1800,
        timeout: float = 120.0,
    ) -> ModelReply:
        self.reset_cancel()
        payload = json.dumps(
            {
                "model": "local-model",
                "messages": messages,
                "temperature": temperature,
                "max_tokens": max_tokens,
                "stream": False,
            }
        ).encode("utf-8")
        connection: http.client.HTTPConnection | None = None
        try:
            connection, path = self._connection_for(self.api_url, timeout)
            with self._connection_lock:
                self._connection = connection
            connection.request(
                "POST",
                path,
                body=payload,
                headers={
                    "Content-Type": "application/json",
                    "Accept": "application/json",
                    "Content-Length": str(len(payload)),
                },
            )
            response = connection.getresponse()
            body = response.read().decode("utf-8", errors="replace")
            if self._cancelled.is_set():
                return ModelReply(False, "", "local-model", "Stopped by the operator.")
            if response.status < 200 or response.status >= 300:
                return ModelReply(
                    False,
                    "",
                    "local-model",
                    f"Local model returned HTTP {response.status}: {body[:1000]}",
                )
            data = json.loads(body)
            choices = data.get("choices") or []
            message = (choices[0].get("message") or {}) if choices else {}
            text = str(message.get("content") or "").strip()
            model = str(data.get("model") or "local-model")
            if not text:
                return ModelReply(False, "", model, "The local model returned no text.", data)
            return ModelReply(True, text, model, "", data)
        except Exception as error:
            if self._cancelled.is_set():
                return ModelReply(False, "", "local-model", "Stopped by the operator.")
            online_hint = ""
            if isinstance(error, (ConnectionRefusedError, TimeoutError, OSError)):
                online_hint = " Start FOXAI Chat Engine and try again."
            return ModelReply(
                False,
                "",
                "local-model",
                f"{type(error).__name__}: {error}.{online_hint}".replace("..", "."),
            )
        finally:
            with self._connection_lock:
                self._connection = None
            if connection is not None:
                try:
                    connection.close()
                except Exception:
                    pass

    @staticmethod
    def generation_messages(user_prompt: str) -> list[dict[str, str]]:
        return [
            {
                "role": "system",
                "content": (
                    "You are FOXAI Dirty Python Lab. Return exactly one complete Python program. "
                    "Do not use Markdown fences. Do not explain the code before or after it. "
                    "Prefer the Python standard library. Work only within the supplied task. "
                    "Assume the program runs from a disposable workspace. Do not install packages, "
                    "modify FOXAI production files, use administrator elevation, alter the registry, "
                    "create services, startup entries, or scheduled tasks."
                ),
            },
            {"role": "user", "content": user_prompt.strip()},
        ]

    @staticmethod
    def build_repair_prompt(
        original_prompt: str,
        previous_program: str,
        result: dict[str, Any],
        attempt_number: int,
        max_attempts: int,
    ) -> str:
        return (
            "Correct the complete Python program for the original task.\n\n"
            f"ORIGINAL TASK:\n{original_prompt.strip()}\n\n"
            f"PREVIOUS COMPLETE PROGRAM:\n{previous_program}\n\n"
            f"ATTEMPT: {attempt_number} OF {max_attempts}\n"
            f"RETURN CODE: {result.get('return_code')}\n"
            f"TIMEOUT: {bool(result.get('timed_out'))}\n"
            f"STOPPED: {bool(result.get('stopped'))}\n\n"
            f"STDOUT:\n{result.get('stdout') or '[empty]'}\n\n"
            f"STDERR:\n{result.get('stderr') or '[empty]'}\n\n"
            "Return one corrected complete Python program only. Do not use Markdown fences. "
            "Do not include an explanation. Preserve the original task and prefer the standard library."
        )

    def generate_program(self, user_prompt: str) -> ModelReply:
        return self._chat(self.generation_messages(user_prompt))

    def repair_program(
        self,
        original_prompt: str,
        previous_program: str,
        result: dict[str, Any],
        attempt_number: int,
        max_attempts: int,
    ) -> tuple[ModelReply, str]:
        repair_prompt = self.build_repair_prompt(
            original_prompt,
            previous_program,
            result,
            attempt_number,
            max_attempts,
        )
        messages = [
            {
                "role": "system",
                "content": (
                    "You repair Python programs using exact execution evidence. Return one complete "
                    "replacement program only. No Markdown fences and no explanation. Prefer the "
                    "standard library and do not modify FOXAI production files or install packages."
                ),
            },
            {"role": "user", "content": repair_prompt},
        ]
        return self._chat(messages), repair_prompt

    @staticmethod
    def extract_candidate(model_text: str) -> str:
        text = (model_text or "").strip().replace("\r\n", "\n")
        fenced = re.search(r"```(?:python|py)?\s*(.*?)```", text, flags=re.I | re.S)
        if fenced:
            text = fenced.group(1).strip()
        if text.lower().startswith("python\n"):
            text = text.split("\n", 1)[1]
        return text.rstrip() + "\n"

