setlocal
title FOXAI Dirty Python Lab V1

set "LAB=Z:\FOXAI\_LAB\DirtyPythonLab"
set "PYTHON=Z:\FOXAI\env\python\python.exe"

if not exist "%PYTHON%" (
    echo.
    echo FOXAI PYTHON WAS NOT FOUND:
    echo %PYTHON%
    echo.
    pause
    exit /b 1
)

if not exist "%LAB%\dirty_python_lab.py" (
    echo.
    echo DIRTY PYTHON LAB WAS NOT FOUND:
    echo %LAB%
    echo.
    pause
    exit /b 1
)

set "PYTHONNOUSERSITE=1"
set "PYTHONDONTWRITEBYTECODE=1"
cd /d "%LAB%"
"%PYTHON%" -B "%LAB%\dirty_python_lab.py"
if errorlevel 1 (
    echo.
    echo Dirty Python Lab closed with an error.
    pause
)
